<script lang="ts">
import type { Snippet } from 'svelte';
import {
  QueryClientProvider,
  QueryClient,
  type QueryClientConfig,
} from '@tanstack/svelte-query';
import type { DialConf } from '@viamrobotics/sdk';
import InternalProvider from './internal-provider.svelte';
import {
  enableQueryLogging,
  disableQueryLogging,
  enableVerboseQueryLogging,
  disableVerboseQueryLogging,
} from '../query-logger';

interface Props {
  config?: QueryClientConfig;
  dialConfigs: Record<string, DialConf>;
  logQueries?:
    | boolean
    | {
        enabled: boolean;
        verbose?: boolean;
      };
  children: Snippet;
}

let { config, dialConfigs, logQueries, children }: Props = $props();

export const client = new QueryClient(config);

$effect(() => {
  if (typeof logQueries === 'boolean') {
    logQueries = { enabled: logQueries };
  }

  if (logQueries?.enabled) {
    enableQueryLogging();
  } else {
    disableQueryLogging();
  }
});

$effect(() => {
  if (typeof logQueries === 'boolean') {
    return;
  }

  if (logQueries?.verbose) {
    enableVerboseQueryLogging();
  } else {
    disableVerboseQueryLogging();
  }
});
</script>

<QueryClientProvider {client}>
  <InternalProvider {dialConfigs}>
    {@render children()}
  </InternalProvider>
</QueryClientProvider>
